#include <vector>

int main() {
    std::vector<std::string> fruits = {"Apple", "Banana"};
    fruits.push_back("Cherry"); // Appends element

    std::cout << "Fruits collection size: " << fruits.size() << "\n";
    for (const auto& fruit : fruits) {
        std::cout << " - " << fruit << "\n";
    }
    return 0;
}

Code Example 2 (Practical):
#include <iostream>
#include <unordered_map>
#include <string>

int main() {
    // Hash map with constant-time lookup O(1)
    std::unordered_map<std::string, double> constantTable;
    constantTable["Gravity"] = 9.81;
    constantTable["Pi"] = 3.14159;
    constantTable["SpeedOfLight"] = 299792458.0;

    std::string query = "Pi";
    if (constantTable.find(query) != constantTable.end()) {
        std::cout << "Lookup: " << query << " = " << constantTable[query] << "\n";
    }

    std::cout << "--- Printing database entries ---\n";
    for (const auto& [name, value] : constantTable) {
         std::cout << name << " -> " << value << "\n";
    }
    return 0;
}

